import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  AreaChart,
  Area
} from 'recharts';
import toast from 'react-hot-toast';

const API_URL = 'http://localhost:5000/api';

function ProductDetail() {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProductDetails();
    // Refresh every 30 seconds
    const interval = setInterval(fetchProductDetails, 30000);
    return () => clearInterval(interval);
  }, [id]);

  const fetchProductDetails = async () => {
    try {
      const response = await axios.get(`${API_URL}/products/${id}`, {
        withCredentials: true
      });
      setProduct(response.data);
    } catch (error) {
      console.error('Error fetching product details:', error);
      toast.error('Failed to load product details');
    } finally {
      setLoading(false);
    }
  };

  const getDecisionColor = (decision) => {
    switch(decision) {
      case 'BUY_NOW': return '#48bb78';
      case 'BUY_SOON': return '#ecc94b';
      default: return '#f56565';
    }
  };

  if (loading) {
    return <div style={{ textAlign: 'center', padding: '50px' }}>Loading...</div>;
  }

  if (!product) {
    return <div style={{ textAlign: 'center', padding: '50px' }}>Product not found</div>;
  }

  return (
    <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
      <div style={{ marginBottom: '30px' }}>
        <h1>{product.name}</h1>
        <a href={product.url} target="_blank" rel="noopener noreferrer" style={{ color: 'var(--text-secondary)' }}>
          View on Store →
        </a>
      </div>

      {/* Recommendation Card */}
      <div style={{
        background: 'var(--bg-secondary)',
        borderRadius: '12px',
        padding: '30px',
        marginBottom: '30px',
        textAlign: 'center',
        borderLeft: `4px solid ${getDecisionColor(product.recommendation.decision)}`
      }}>
        <div style={{ fontSize: '1.5rem', marginBottom: '10px' }}>
          AI Recommendation
        </div>
        <div style={{
          fontSize: '2rem',
          fontWeight: 'bold',
          color: getDecisionColor(product.recommendation.decision),
          marginBottom: '10px'
        }}>
          {product.recommendation.decision === 'BUY_NOW' ? '🟢 BUY NOW' :
           product.recommendation.decision === 'BUY_SOON' ? '🟡 BUY BEFORE INCREASE' :
           '🔴 WAIT'}
        </div>
        <div style={{ marginBottom: '10px' }}>
          Confidence Score: {product.recommendation.confidence}%
        </div>
        <div style={{ color: 'var(--text-secondary)' }}>
          {product.recommendation.reasoning}
        </div>
      </div>

      {/* Price Info */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
        gap: '20px',
        marginBottom: '30px'
      }}>
        <div className="chart-container">
          <h3>Current Price</h3>
          <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: '#48bb78' }}>
            ${product.current_price}
          </div>
          {product.original_price && (
            <div style={{ textDecoration: 'line-through', color: 'var(--text-secondary)' }}>
              Original: ${product.original_price}
            </div>
          )}
        </div>

        <div className="chart-container">
          <h3>Discount Analysis</h3>
          <div style={{ fontSize: '1.2rem', marginBottom: '10px' }}>
            {product.discount_info.is_genuine ? '✅ Genuine Discount' : '⚠️ Fake Discount Warning'}
          </div>
          <div>Discount: {product.discount_info.discount_percentage}%</div>
          <div style={{ fontSize: '0.9rem', marginTop: '10px' }}>
            {product.discount_info.message}
          </div>
        </div>

        <div className="chart-container">
          <h3>Seller Analysis</h3>
          <div>{product.seller_insights.message}</div>
          <div style={{ fontSize: '0.9rem', marginTop: '10px' }}>
            Next move: {product.seller_insights.next_move_prediction}
          </div>
        </div>
      </div>

      {/* Price History Chart */}
      <div className="chart-container">
        <h3>Price History</h3>
        <ResponsiveContainer width="100%" height={400}>
          <LineChart data={product.price_history}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="date" />
            <YAxis />
            <Tooltip />
            <Legend />
            <Line type="monotone" dataKey="price" stroke="#48bb78" name="Actual Price" />
          </LineChart>
        </ResponsiveContainer>
      </div>

      {/* Price Prediction Chart */}
      {product.predictions && product.predictions.prices && (
        <div className="chart-container">
          <h3>Price Prediction (Next 7 Days)</h3>
          <ResponsiveContainer width="100%" height={400}>
            <AreaChart data={product.predictions.dates.map((date, idx) => ({
              date: new Date(date).toLocaleDateString(),
              predicted: product.predictions.prices[idx],
              lower: product.predictions.lower_bound[idx],
              upper: product.predictions.upper_bound[idx]
            }))}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="date" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Area type="monotone" dataKey="predicted" stroke="#ecc94b" fill="#ecc94b" fillOpacity={0.3} name="Predicted Price" />
              <Area type="monotone" dataKey="upper" stroke="transparent" fill="transparent" />
              <Area type="monotone" dataKey="lower" stroke="transparent" fill="transparent" />
            </AreaChart>
          </ResponsiveContainer>
          <div style={{ marginTop: '10px', textAlign: 'center' }}>
            Trend: {product.predictions.trend}
          </div>
        </div>
      )}
    </div>
  );
}

export default ProductDetail;
